async def show_lang_menu(reply_func, lang):
    keyboard = [
        [InlineKeyboardButton("🇷🇺 Русский", callback_data="setlang|ru")],
        [InlineKeyboardButton("🇰🇿 Қазақша", callback_data="setlang|kk")],
    ]
    await reply_func(t(lang, "choose_lang"), reply_markup=InlineKeyboardMarkup(keyboard))

# ══════════════════════════════════════════════
# ВЫБОР ПРЕДМЕТА ДЛЯ ТЕСТА
# ══════════════════════════════════════════════
async def show_test_subject_menu(reply_func, user):
    lang = get_lang(user)
    if not has_test_access(user):
        keyboard = [[InlineKeyboardButton(t(lang, "btn_buy_test"), callback_data="buy_premium_test")]]
        await reply_func(t(lang, "test_intro_locked"), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
        return

    reset_daily_if_needed(user)
    remaining = TEST_DAILY_LIMIT - user["test_today"]
    if remaining <= 0:
        await reply_func(t(lang, "test_limit_reached", limit=TEST_DAILY_LIMIT))
        return

    keyboard = [[InlineKeyboardButton(subject_to_display(s, lang), callback_data=f"test_subject|{s}")] for s in SUBJECTS]
    keyboard.append([InlineKeyboardButton(t(lang, "btn_all_subjects"), callback_data="test_subject|all")])

    await reply_func(
        t(lang, "test_choose_subject", remaining=remaining, limit=TEST_DAILY_LIMIT),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(keyboard)
    )

# ══════════════════════════════════════════════
# МЕНЮ — ОБРАБОТЧИК КНОПОК
# ══════════════════════════════════════════════
async def menu_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text
    uid = update.effective_user.id

    # Админ вводит ID пользователя для активации подписки
    if uid == ADMIN_ID and context.user_data.get("awaiting_activate_id"):
        context.user_data["awaiting_activate_id"] = False
        target_id = text.strip()
        if not target_id.isdigit():
            await update.message.reply_text("⚠️ Это не похоже на ID (должно быть число). Попробуй ещё раз через /admin")
            return
        keyboard = [
            [InlineKeyboardButton("⭐️ Стандарт (790 ₸)", callback_data=f"adm_act|{target_id}|standard")],
            [InlineKeyboardButton("⭐️ Премиум (990 ₸)", callback_data=f"adm_act|{target_id}|premium")],
            [InlineKeyboardButton("🧪 Премиум+Тест (1590 ₸)", callback_data=f"adm_act|{target_id}|premium_test")],
        ]
        await update.message.reply_text(
            f"Выбери тариф для активации пользователю `{target_id}` 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(keyboard)
        )
        return

    if text.lower() in ("start", "старт", "/start", "начать", "начало", "бастау"):
        await start(update, context)
        return

    users = load_users()
    user = get_user(users, uid)
    lang = get_lang(user)

    if text == t(lang, "btn_question"):
        await send_question(context.bot, uid)

    elif text == t(lang, "btn_test"):
        await show_test_subject_menu(update.message.reply_text, user)

    elif text == t(lang, "btn_premium"):
        await show_premium_menu(update.message.reply_text, user)

    elif text == t(lang, "btn_stats"):
        await update.message.reply_text(get_stats_text(user), parse_mode="Markdown")

    elif text == t(lang, "btn_lang"):
        await show_lang_menu(update.message.reply_text, lang)

    elif text == t(lang, "btn_help"):
        await update.message.reply_text(t(lang, "help_text"), parse_mode="Markdown")

    elif text == "🛠 Админ-панель" and uid == ADMIN_ID:
        await show_admin_panel(update.message.reply_text)

    else:
        await update.message.reply_text(t(lang, "use_menu"), reply_markup=main_menu(lang, is_admin=(uid == ADMIN_ID)))

# ══════════════════════════════════════════════
# ПРЕМИУМ МЕНЮ
# ══════════════════════════════════════════════
async def show_premium_menu(reply_func, user=None):
    lang = get_lang(user) if user else "ru"
    if user and is_premium(user):
        plan = user.get("plan", "free")
        until = datetime.fromisoformat(user["plan_until"]).strftime("%d.%m.%Y")

        if plan == "premium_test":
            await reply_func(t(lang, "premium_max", until=until), parse_mode="Markdown")
            return

        if plan == "premium":
            keyboard = [[InlineKeyboardButton(t(lang, "btn_upgrade_test"), callback_data="buy_premium_test")]]
            await reply_func(t(lang, "premium_upsell_to_test", until=until), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
            return

        if plan == "standard":
            keyboard = [
                [InlineKeyboardButton(t(lang, "btn_upgrade_premium"), callback_data="buy_premium")],
                [InlineKeyboardButton(t(lang, "btn_upgrade_test"), callback_data="buy_premium_test")],
            ]
            await reply_func(t(lang, "standard_upsell", until=until), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
            return

    keyboard = [
        [InlineKeyboardButton(t(lang, "btn_buy_standard"), callback_data="buy_standard")],
        [InlineKeyboardButton(t(lang, "btn_buy_premium"), callback_data="buy_premium")],
        [InlineKeyboardButton(t(lang, "btn_buy_test"), callback_data="buy_premium_test")],
    ]
    await reply_func(t(lang, "tariffs_full"), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))

# ══════════════════════════════════════════════
# CALLBACK КНОПКИ
# ══════════════════════════════════════════════
async def button_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    data = query.data

    if data.startswith("setlang|"):
        _, new_lang = data.split("|")
        users = load_users()
        user = get_user(users, query.from_user.id)
        user["lang"] = new_lang
        save_users(users)
        await query.message.reply_text(t(new_lang, "lang_set"), reply_markup=main_menu(new_lang, is_admin=(query.from_user.id == ADMIN_ID)))
        return

    if data == "show_premium":
        users = load_users()
        user = get_user(users, query.from_user.id)
        await show_premium_menu(query.message.reply_text, user)
        return

    if data.startswith("test_subject|"):
        _, subject = data.split("|", 1)
        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        if not has_test_access(user):
            await query.message.reply_text(t(lang, "test_no_access"), parse_mode="Markdown")
            return
        user["test_subject"] = subject
        user["test_mode"] = True
        save_users(users)
        label = t(lang, "all_subjects_label") if subject == "all" else subject_to_display(subject, lang)
        await query.message.reply_text(t(lang, "test_started", label=label), parse_mode="Markdown")
        await send_test_question(context.bot, query.from_user.id)
        return

    if data in ("buy_standard", "buy_premium", "buy_premium_test"):
        plan = data.replace("buy_", "")
        price = PLAN_PRICES[plan]
        plan_name = PLAN_NAMES[plan]

        users = load_users()
        user = get_user(users, query.from_user.id)
        lang = get_lang(user)
        user["pending_payment"] = plan
        save_users(users)

        text = t(lang, "payment_text", plan_name=plan_name, price=price, kaspi=KASPI_NUMBER, uid=query.from_user.id)
        keyboard = [[InlineKeyboardButton(t(lang, "btn_paid"), callback_data=f"paid|{plan}|{price}")]]
        await query.message.reply_text(text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))
        return

    if data.startswith("paid|"):
        _, plan, price = data.split("|")
        uid = query.from_user.id
        raw_name = query.from_user.first_name or "Пользователь"
        safe_name = re.sub(r'[*_`\[\]]', '', raw_name)
        username = f"@{query.from_user.username}" if query.from_user.username else "без юзернейма"
        plan_name = PLAN_NAMES.get(plan, plan)

        users = load_users()
        user = get_user(users, uid)
        lang = get_lang(user)

        admin_text = (
            f"💰 *Новая оплата!*\n\n"
            f"👤 {safe_name} ({username})\n"
            f"🆔 ID: `{uid}`\n"
            f"📦 Тариф: {plan_name}\n"
            f"💵 Сумма: {price} ₸\n\n"
            f"Подтверди оплату на Kaspi и нажми кнопку 👇"
        )
        admin_keyboard = [[
            InlineKeyboardButton(f"✅ Активировать {plan_name}", callback_data=f"adm_act|{uid}|{plan}")
        ]]
        try:
            await context.bot.send_message(
                chat_id=ADMIN_ID, text=admin_text, parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(admin_keyboard)
            )
        except Exception as e:
            logger.error(f"Не удалось уведомить админа: {e}")
            try:
                plain_text = f"Новая оплата!\n\n{safe_name} ({username})\nID: {uid}\nТариф: {plan_name}\nСумма: {price} тг"
                await context.bot.send_message(chat_id=ADMIN_ID, text=plain_text, reply_markup=InlineKeyboardMarkup(admin_keyboard))
            except Exception as e2:
                logger.error(f"Запасной вариант тоже не сработал: {e2}")

        support_keyboard = [[InlineKeyboardButton(t(lang, "btn_support"), url=f"https://t.me/{SUPPORT_USERNAME}")]]
        await query.message.reply_text(
            t(lang, "paid_confirm"), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(support_keyboard)
        )
        return

    if data == "adm_users":
        if query.from_user.id != ADMIN_ID:
            return
        await send_users_list(query.message.reply_text)
        return

    if data == "adm_refresh":
        if query.from_user.id != ADMIN_ID:
            return
        await do_refresh_menu(query.message.reply_text, context.bot)
        return

    if data == "adm_activate_start":
        if query.from_user.id != ADMIN_ID:
            return
        context.user_data["awaiting_activate_id"] = True
        await query.message.reply_text(
            "✏️ Пришли Telegram ID пользователя для активации (просто числом).\n\n"
            "Например: 123456789"
        )
        return

    if data.startswith("adm_act_choose|"):
        if query.from_user.id != ADMIN_ID:
            return
        _, target_uid = data.split("|")
        keyboard = [
            [InlineKeyboardButton("⭐️ Стандарт (790 ₸)", callback_data=f"adm_act|{target_uid}|standard")],
            [InlineKeyboardButton("⭐️ Премиум (990 ₸)", callback_data=f"adm_act|{target_uid}|premium")],
            [InlineKeyboardButton("🧪 Премиум+Тест (1590 ₸)", callback_data=f"adm_act|{target_uid}|premium_test")],
        ]
        await query.message.reply_text(
            f"Выбери тариф для активации пользователю `{target_uid}` 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(keyboard)
        )
        return

    if data.startswith("adm_act|"):
        if query.from_user.id != ADMIN_ID:
            return
        _, target_uid, plan = data.split("|")
        users = load_users()
        user = get_user(users, target_uid)
        user["plan"] = plan
        user["plan_until"] = (datetime.now() + timedelta(days=30)).isoformat()
        user["pending_payment"] = None
        save_users(users)
        plan_name = PLAN_NAMES[plan]
        exp_date = (datetime.now() + timedelta(days=30)).strftime("%d.%m.%Y")
        target_lang = get_lang(user)

        extra = t(target_lang, "activated_extra_test") if plan == "premium_test" else ""
        notice = t(target_lang, "activated", plan_name=plan_name, exp_date=exp_date, extra=extra)
        try:
            await context.bot.send_message(
                chat_id=int(target_uid), text=notice, parse_mode="Markdown", reply_markup=main_menu(target_lang)
            )
            await query.edit_message_text(f"✅ Активировано: {plan_name} для {target_uid} до {exp_date}\n(клиент уведомлён)")
        except Exception as e:
            await query.edit_message_text(f"✅ Активировано: {plan_name} до {exp_date}\n❌ Клиент не уведомлён: {e}")
        return

    if data.startswith("ans|"):
        parts = data.split("|")
        if len(parts) < 6:
            return
        _, chat_id, subject, idx, chosen, mode = parts
        idx = int(idx); chat_id = int(chat_id)
        users = load_users()
        user = get_user(users, chat_id)
        lang = get_lang(user)

        q_ru = QUESTIONS_RU[subject][idx]
        is_correct = chosen == q_ru["ans"]
        q_display = QUESTIONS_BY_LANG[lang][subject_to_display(subject, lang)][idx] if lang == "kk" else q_ru

        st = user["stats"].setdefault(subject, {"correct": 0, "total": 0})
        st["total"] += 1
        if is_correct:
            st["correct"] += 1
        save_users(users)

        display_subject = subject_to_display(subject, lang)
        correct_letter = q_ru['ans']
        correct_full_text = next((opt for opt in q_display['opts'] if opt.startswith(correct_letter)), correct_letter)
        safe_user_name = user.get('name') or ("Ученик" if lang == "ru" else "Оқушы")
        result = t(lang, "correct", name=safe_user_name, ans=correct_full_text) if is_correct else t(lang, "incorrect", chosen=chosen, ans=correct_full_text)
        result += t(lang, "explanation", exp=q_display['exp'])
        result += f"\n\n📊 {display_subject}: {st['correct']}/{st['total']}"
        await query.edit_message_reply_markup(reply_markup=None)
        await context.bot.send_message(chat_id=chat_id, text=result, parse_mode="Markdown")

        if mode == "test":
            users = load_users()
            user = get_user(users, chat_id)
            if has_test_access(user) and can_get_test_question(user):
                await send_test_question(context.bot, chat_id)
            elif has_test_access(user):
                lang2 = get_lang(user)
                await context.bot.send_message(chat_id=chat_id, text=t(lang2, "test_finished", limit=TEST_DAILY_LIMIT))

# ══════════════════════════════════════════════
# АДМИН КОМАНДЫ
# ══════════════════════════════════════════════
async def activate_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        await update.message.reply_text(f"Нет доступа. Твой ID: {update.effective_user.id}")
        return
    args = context.args
    if len(args) < 2:
        await update.message.reply_text("Использование: /activate [user_id] [standard|premium|premium_test]")
        return
    target_uid, plan = args[0], args[1]
    if plan not in ("standard", "premium", "premium_test"):
        await update.message.reply_text("План: standard, premium или premium_test")
        return
    users = load_users()
    user = get_user(users, target_uid)
    user["plan"] = plan
    user["plan_until"] = (datetime.now() + timedelta(days=30)).isoformat()
    user["pending_payment"] = None
    save_users(users)
    plan_name = PLAN_NAMES[plan]
    exp_date = (datetime.now() + timedelta(days=30)).strftime("%d.%m.%Y")
    target_lang = get_lang(user)

    extra = t(target_lang, "activated_extra_test") if plan == "premium_test" else ""
    notice = t(target_lang, "activated", plan_name=plan_name, exp_date=exp_date, extra=extra)
    try:
        await context.bot.send_message(
            chat_id=int(target_uid), text=notice, parse_mode="Markdown", reply_markup=main_menu(target_lang)
        )
        await update.message.reply_text(f"✅ Активировано и отправлено: {plan_name} для {target_uid} до {exp_date}")
    except Exception as e:
        await update.message.reply_text(f"✅ Активировано: {plan_name} до {exp_date}\n❌ Сообщение не дошло: {e}")

async def users_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    await send_users_list(update.message.reply_text)

async def send_users_list(reply_func):
    users = load_users()
    premium_count = sum(1 for u in users.values() if is_premium(u))
    lines = [f"👥 *Всего: {len(users)} | ⭐️ Премиум: {premium_count} | 🆓 Бесплатных: {len(users)-premium_count}*\n"]
    for uid, u in users.items():
        lang_flag = "🇰🇿" if u.get("lang") == "kk" else "🇷🇺"
        if is_premium(u):
            until = datetime.fromisoformat(u["plan_until"]).strftime("%d.%m")
            plan_label = PLAN_NAMES.get(u.get("plan"), u.get("plan"))
            lines.append(f"⭐️{lang_flag} {u.get('name','?')} `{uid}` — {plan_label} до {until}")
        else:
            lines.append(f"🆓{lang_flag} {u.get('name','?')} `{uid}`")
    await reply_func("\n".join(lines), parse_mode="Markdown")

async def refresh_menu_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    await do_refresh_menu(update.message.reply_text, context.bot)

async def do_refresh_menu(reply_func, bot):
    users = load_users()
    sent, failed = 0, 0
    await reply_func(f"🔄 Обновляю меню у {len(users)} пользователей...")
    for uid, u in users.items():
        try:
            lang = get_lang(u)
            text = "🔄 Меню обновлено!" if lang == "ru" else "🔄 Мәзір жаңартылды!"
            await bot.send_message(chat_id=int(uid), text=text, parse_mode="Markdown", reply_markup=main_menu(lang))
            sent += 1
            await asyncio.sleep(0.3)
        except Exception as e:
            failed += 1
            logger.warning(f"Не удалось обновить меню {uid}: {e}")
    await reply_func(f"✅ Готово! Отправлено: {sent}, ошибок: {failed}")

# ══════════════════════════════════════════════
# АДМИН-ПАНЕЛЬ
# ══════════════════════════════════════════════
async def admin_panel_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    await show_admin_panel(update.message.reply_text)

async def show_admin_panel(reply_func):
    users = load_users()
    premium_count = sum(1 for u in users.values() if is_premium(u))
    text = (
        f"🛠 *Админ-панель*\n\n"
        f"👥 Всего пользователей: *{len(users)}*\n"
        f"⭐️ Премиум: *{premium_count}* | 🆓 Бесплатных: *{len(users)-premium_count}*\n\n"
        f"Выбери действие 👇"
    )
    keyboard = [
        [InlineKeyboardButton("👥 Список пользователей", callback_data="adm_users")],
        [InlineKeyboardButton("🔄 Обновить меню у всех", callback_data="adm_refresh")],
        [InlineKeyboardButton("✅ Активировать подписку", callback_data="adm_activate_start")],
    ]
    await reply_func(text, parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(keyboard))


# ══════════════════════════════════════════════
# РАССЫЛКА
# ══════════════════════════════════════════════
async def broadcast(context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    for uid, user in users.items():
        if user.get("broadcast", True):
            try:
                await send_question(context.bot, int(uid))
                await asyncio.sleep(0.3)
            except Exception as e:
                logger.warning(f"Ошибка {uid}: {e}")

# ══════════════════════════════════════════════
# MAIN
# ══════════════════════════════════════════════
def main():
    app = Application.builder().token(TOKEN).build()

    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("activate", activate_cmd))
    app.add_handler(CommandHandler("users", users_cmd))
    app.add_handler(CommandHandler("refresh_menu", refresh_menu_cmd))
    app.add_handler(CommandHandler("admin", admin_panel_cmd))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, menu_handler))
    app.add_handler(CallbackQueryHandler(button_callback))

    app.job_queue.run_daily(broadcast, time=dtime(8, 0, tzinfo=ALMATY_TZ))
    app.job_queue.run_daily(broadcast, time=dtime(12, 0, tzinfo=ALMATY_TZ))
    app.job_queue.run_daily(broadcast, time=dtime(15, 0, tzinfo=ALMATY_TZ))
    app.job_queue.run_daily(broadcast, time=dtime(18, 0, tzinfo=ALMATY_TZ))
    app.job_queue.run_daily(broadcast, time=dtime(21, 0, tzinfo=ALMATY_TZ))

    logger.info("Бот запущен!")
    app.run_polling(allowed_updates=Update.ALL_TYPES)

if __name__ == "__main__":
    main()
